query:
-- First, get the Novlan Ford dealer ID
SET @novlan_id = (SELECT id FROM dealers WHERE slug = 'https---novlanbros-com-ford-' LIMIT 1);

-- Delete generated content for other dealers
DELETE FROM generatedContent WHERE dealerId != @novlan_id;

-- Delete Facebook ads for other dealers
DELETE FROM facebookAds WHERE dealerId != @novlan_id;

-- Delete inventory items for other dealers
DELETE FROM inventoryItems WHERE dealerId != @novlan_id;

-- Delete other dealers
DELETE FROM dealers WHERE id != @novlan_id;

